      }
    });

    return {
      safe: warnings.length === 0,
      warnings,
    };
  }

  /**
   * Redact environment variables
   */
  static redactEnv(env) {
    const redacted = {};

    Object.keys(env).forEach(key => {
      const value = env[key];
      if (!value) {
        redacted[key] = '';
