      }

      const lowerKey = key.toLowerCase();
      const isSensitive = lowerKey.includes('key') ||
                         lowerKey.includes('token') ||
                         lowerKey.includes('secret') ||
                         lowerKey.includes('password');

      if (isSensitive) {
        redacted[key] = value.length > 8
          ? `${value.substring(0, 4)}...[REDACTED]`
          : '[REDACTED]';
      } else {
        redacted[key] = value;
      }
    });

    return redacted;
  }
}

